import{H as e,V as t,et as n,j as r}from"./chunks/framework.C_EfTa_6.js";var i=JSON.parse(`{"title":"硬件","description":"","frontmatter":{"title":"硬件","order":15},"headers":[],"relativePath":"ai/compute/deploy/hardware.md","filePath":"ai/compute/deploy/hardware.md"}`),a={name:`ai/compute/deploy/hardware.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="gpu-ai-部署参考" tabindex="-1">GPU AI 部署参考 <a class="header-anchor" href="#gpu-ai-部署参考" aria-label="Permalink to “GPU AI 部署参考”">​</a></h1><p>选购 GPU 跑 AI 时，硬件规格只是故事的一半——架构代际决定模型能否正确运行，软件生态决定实际体验。本文从架构要求、NVLink 互联、AMD 生态和魔改卡风险四个维度，提供面向 AI 部署的 GPU 选型参考。</p><h2 id="gpu-架构硬性要求" tabindex="-1">GPU 架构硬性要求 <a class="header-anchor" href="#gpu-架构硬性要求" aria-label="Permalink to “GPU 架构硬性要求”">​</a></h2><p>显存容量只决定模型能否装下，架构代际决定模型能否正确运行。很多看似&quot;显存够&quot;的卡实际上跑不了现代 LLM。</p><p>BF16 支持是硬门槛。目前绝大多数开源大模型（Llama 3/4、Qwen 2.5/3.6、DeepSeek-V3）的预训练权重均为 BF16 格式。BF16 的数值动态范围与 FP32 相同（8 位指数），在 Attention 的 Softmax 阶段不会发生数值溢出。FP16 的指数位只有 5 位，动态范围窄，处理大模型的长序列 Attention 时极易出现 NaN 或乱码。NVIDIA 从 Ampere 架构（RTX 30 系列、A100）开始才硬件支持 BF16。</p><p>FlashAttention-2 是长上下文的基石。FA2 通过分块计算和重排内存访问模式，将注意力计算的显存带宽利用率从 20% 提升到 80%+。FA2 需要 sm_80（Ampere）及以上的 CUDA 算力。</p><table tabindex="0"><thead><tr><th>架构</th><th>代表显卡</th><th>CUDA SM</th><th style="text-align:center;">BF16</th><th style="text-align:center;">FA2</th><th style="text-align:center;">FP8</th><th>LLM 可用性</th></tr></thead><tbody><tr><td>Volta</td><td>V100</td><td>sm_70</td><td style="text-align:center;">否</td><td style="text-align:center;">否</td><td style="text-align:center;">否</td><td>靠 FP32 勉强跑，长上下文不可用</td></tr><tr><td>Turing</td><td>2080 Ti, TITAN RTX</td><td>sm_75</td><td style="text-align:center;">否</td><td style="text-align:center;">部分</td><td style="text-align:center;">否</td><td>量化模型勉强跑，FA2 缺失拖慢长序列</td></tr><tr><td>Ampere</td><td>3090, A6000, A100</td><td>sm_80/86</td><td style="text-align:center;">是</td><td style="text-align:center;">是</td><td style="text-align:center;">部分</td><td>本地部署的推荐底线</td></tr><tr><td>Ada Lovelace</td><td>4090, RTX 6000 Ada</td><td>sm_89</td><td style="text-align:center;">是</td><td style="text-align:center;">是</td><td style="text-align:center;">是</td><td>FP8 native，当前消费级最优</td></tr><tr><td>Hopper</td><td>H100</td><td>sm_90</td><td style="text-align:center;">是</td><td style="text-align:center;">是 (FA3)</td><td style="text-align:center;">是</td><td>数据中心旗舰</td></tr></tbody></table><p>结论：本地 LLM 部署的架构底线是 Ampere（3090 及以上）。2080 Ti 和 V100 虽然显存规格不低（改版可达 22GB/32GB），但缺少 BF16 和 FA2 支持使得实际可用性极差——能把模型加载起来但随时可能输出 NaN、长文本推理卡顿、量化工具兼容性差。</p><h2 id="nvlink-桥接参考" tabindex="-1">NVLink 桥接参考 <a class="header-anchor" href="#nvlink-桥接参考" aria-label="Permalink to “NVLink 桥接参考”">​</a></h2><p>NVLink 是 NVIDIA 的卡间直连技术，提供远超 PCIe 的通信带宽，对张量并行的多卡推理至关重要。Ada Lovelace（RTX 40 系列）及之后的架构已在消费级和专业级卡上全面移除 NVLink 物理接口——支持 NVLink 的卡集中在 Ampere 及更早代际。</p><table tabindex="0"><thead><tr><th>架构</th><th>支持 NVLink 的型号</th><th>桥接规格</th><th>双向带宽</th></tr></thead><tbody><tr><td>Ampere</td><td>RTX 3090, 3090 Ti, RTX A6000, A5500, A5000, A4500</td><td>3 代桥接器 (3-Slot / 4-Slot)</td><td>112.5 GB/s</td></tr><tr><td>Turing</td><td>TITAN RTX, 2080 Ti, 2080 S, 2080, 2070 S; Quadro RTX 8000/6000/5000</td><td>2 代桥接器</td><td>50-100 GB/s</td></tr><tr><td>Volta</td><td>Quadro GV100</td><td>1/2 代桥接器</td><td>—</td></tr></tbody></table><p>桥接器槽位间距必须与主板 PCIe 插槽物理间距匹配（3-Slot 或 4-Slot），且不可跨架构混用（3090 不能用 Turing 桥接器）。Linux 下对 NVLink P2P 显存共享支持最完善，NCCL 可直接识别；Windows 下部分消费级卡可能受软件层面的 P2P 限制。</p><p>不具备 NVLink 的卡多卡通信必须走 PCIe，可通过开启 PCIe P2P、优化 NCCL 参数（<code>NCCL_P2P_DISABLE=0</code>）、优先使用流水线并行替代张量并行来降低通信瓶颈。多卡并行的具体策略见<a href="./multi-gpu">多卡推理</a>。</p><h2 id="amd-显卡-ai-部署分析" tabindex="-1">AMD 显卡 AI 部署分析 <a class="header-anchor" href="#amd-显卡-ai-部署分析" aria-label="Permalink to “AMD 显卡 AI 部署分析”">​</a></h2><p>AMD 消费级和专业级显卡在纸面硬件规格上对同价位 NVIDIA 卡有优势——7900 XTX 的显存带宽（960 GB/s）甚至略超 3090（936 GB/s），W7900 的 48GB 显存是单卡跑 70B 大模型的物理门票。但硬件规格只是故事的一半，软件生态决定实际体验。</p><table tabindex="0"><thead><tr><th>维度</th><th>RTX 3090 (24G)</th><th>RX 7900 XTX (24G)</th><th>W7800 (32G)</th><th>W7900 (48G)</th></tr></thead><tbody><tr><td>显存带宽</td><td>936 GB/s</td><td>960 GB/s</td><td>576 GB/s</td><td>864 GB/s</td></tr><tr><td>BF16/FP16 算力</td><td>~142 TFLOPS</td><td>~123 TFLOPS</td><td>~90 TFLOPS</td><td>~123 TFLOPS</td></tr><tr><td>CUDA/ROCm 生态</td><td>原生完美支持</td><td>ROCm 适配中</td><td>ROCm 适配中</td><td>ROCm 适配中</td></tr><tr><td>单卡跑 70B INT4</td><td>装不下</td><td>装不下</td><td>勉强</td><td>可以</td></tr><tr><td>多卡并行</td><td>NCCL 稳定</td><td>RCCL 不够成熟</td><td>RCCL 不够成熟</td><td>RCCL 不够成熟</td></tr></tbody></table><p>ROCm 是 AMD 的 GPU 计算平台，对标 CUDA。ROCm 6.x 对 RDNA 3（gfx1100）的支持比早期版本好了很多，Linux 下已能运行 PyTorch 和 vLLM，但实际落地中存在几个痛点：</p><p>FlashAttention-2 的 ROCm 移植分支性能和稳定性不如 NVIDIA 原生 Tensor Core 实现，长文本 Prefill 阶段首字延迟会明显落后于 3090。AWQ/GPTQ 量化模型在 vLLM-ROCm 下经常因为量化 Kernel 未对 RDNA 3 优化，实际推理速度低于理论带宽应有的表现。多卡通信库 RCCL 在消费级 RDNA 3 卡上的 P2P 支持不够稳定，跨卡通信开销大于同级别 NVIDIA 平台。</p><p>AMD 的亮点在 llama.cpp。llama.cpp 的 HIP/ROCm 后端适配非常成熟——通过 <code>cmake -DGGML_HIPBLAS=ON</code> 编译后，在 RDNA 3 上的 GGUF 量化模型运行稳定性与 NVIDIA 卡几乎无异，高显存带宽能得到接近满额的发挥。如果你主要使用 GGUF 格式做本地推理，AMD 7000 系列的性价比会凸显。</p><p>选型建议：追求省心、最新算法（AWQ/FP8/FlashAttention-3）和稳定多卡并行时，3090 是无脑首选。需要单卡 48GB 显存跑 70B 模型（省去多卡 PCIe 通信和 PP/TP 调度开销）且能接受 ROCm 调优成本时，W7900 有不可替代的物理优势。7900 XTX 虽然价格有优势，但在同 24GB 显存级别下，软件生态的劣势抹平了硬件参数的优势，不如直接买二手 3090。</p><h2 id="魔改卡风险" tabindex="-1">魔改卡风险 <a class="header-anchor" href="#魔改卡风险" aria-label="Permalink to “魔改卡风险”">​</a></h2><p>魔改卡（换显存颗粒扩容）不适合 AI 7×24 满载场景。以 3080 20G 魔改版为例：显存带宽仅 760 GB/s（3090 为 936 GB/s，慢 19%），大模型推理是 Memory-Bound 任务，这个差距直接体现在 Token 生成速度上。更致命的是手工 BGA 焊接 GDDR6X 颗粒——满载时显存温度极易突破 100°C 导致降频或掉卡（NVML Critical Error），且部分魔改卡需要定制驱动 INF 文件，新 CUDA 版本和 Docker 镜像可能不兼容。</p><p>3080 本身硬件不支持 NVLink，多卡通信只能走 PCIe。AI 节点最忌讳跑着跑着突然掉卡断流——魔改卡只适合个人 PC 单卡轻度折腾，不建议用于严肃的 AI 服务器。对于多卡 AI 服务器，优先选择正品 RTX 3090 24G（完整显存、更高带宽、官方驱动生态和 7×24 稳定性）。</p><p>常见魔改型号包括：4090 48G、4090D 48G、4080 32G、3080 20G、2080 Ti 22G。完整 GPU 型号参考见 <a href="/kernel/equip/gpu">GPU 硬件</a>。</p>`,24)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};